// Get JSON input
const data = $input.first().json;

// Extract organic results
const results = data.organic_results || [];

const output = results.map(result => {
  return {
    json: {
      title: result.title || "",
      link: result.link || "",
      displayed_link: result.displayed_link || ""
    }
  };
});

return output;

// n8n Code node (Run once for each item)
// Input esperado: HTML string en $json.body o $json.data o $json.html
// Output: titleExact, subtitle, author, link

const html = $json.body ?? $json.data ?? $json.html ?? "";
const fallbackUrl = $json.bestUrl ?? $json.url ?? "";

if (!html || typeof html !== "string") {
  return [{ json: { error: "No HTML string found", link: fallbackUrl } }];
}

function extractJsonLd(htmlStr) {
  const matches = [...htmlStr.matchAll(
    /<script[^>]+type=["']application\/ld\+json["'][^>]*>([\s\S]*?)<\/script>/gi
  )];

  const parsed = [];
  for (const m of matches) {
    const raw = (m[1] || "").trim();
    if (!raw) continue;

    try {
      const clean = raw.replace(/<!--|-->/g, "").trim();
      const data = JSON.parse(clean);
      if (Array.isArray(data)) parsed.push(...data);
      else parsed.push(data);
    } catch (_) {}
  }
  return parsed;
}

function flattenGraph(objs) {
  const flat = [];
  for (const o of objs) {
    if (!o) continue;
    if (o["@graph"] && Array.isArray(o["@graph"])) flat.push(...o["@graph"]);
    else flat.push(o);
  }
  return flat;
}

function hasType(o, t) {
  const ty = o?.["@type"];
  if (!ty) return false;
  if (Array.isArray(ty)) return ty.map(String).includes(t);
  return String(ty) === t;
}

function pickBest(flat) {
  return flat.find(o => hasType(o, "Book"))
    || flat.find(o => hasType(o, "Product"))
    || flat[0]
    || null;
}

function normalizeAuthor(a) {
  if (!a) return "";
  if (typeof a === "string") return a;
  if (Array.isArray(a)) {
    return a.map(x => (typeof x === "string" ? x : x?.name)).filter(Boolean).join(", ");
  }
  if (typeof a === "object") return a.name || "";
  return "";
}

function smartTitleCaseEs(input) {
  if (!input) return "";
  const s = String(input).trim().replace(/\s+/g, " ");
  if (!s) return "";

  // Stopwords (nunca son siglas, aunque vengan en may첬sculas)
  const lowerWords = new Set([
    "a","al","ante","bajo","cabe","con","contra","de","del","desde","durante","en","entre",
    "hacia","hasta","la","las","el","los","y","e","o","u","ni","que","por","para",
    "sin","sobre","tras","un","una","unos","unas"
  ]);

  // Detecta si viene "gritado" o con demasiadas may첬sculas
  const letters = s.replace(/[^A-Za-z횁횋횒횙횣횥횗찼챕챠처첬체챰]/g, "");
  const upperLetters = letters.replace(/[^A-Z횁횋횒횙횣횥횗]/g, "");
  const ratioUpper = letters.length ? upperLetters.length / letters.length : 0;

  // Si no parece grito, no tocar
  if (ratioUpper < 0.60) return s;

  function isAcronym(token) {
    const clean = token.replace(/[^A-Za-z횁횋횒횙횣횥횗]/g, "");
    if (clean.length < 2 || clean.length > 5) return false;

    // Si es una stopword ("LA", "DE", "LAS"...), NO es sigla
    const asLower = clean.toLowerCase();
    if (lowerWords.has(asLower)) return false;

    return clean === clean.toUpperCase();
  }

  function titleCaseWord(word, isFirstWord) {
    const w = word.toLowerCase();
    if (!isFirstWord && lowerWords.has(w)) return w;
    return w.charAt(0).toUpperCase() + w.slice(1);
  }

  const tokens = s.split(" ");

  const out = tokens.map((tok, idx) => {
    if (!/[A-Za-z횁횋횒횙횣횥횗찼챕챠처첬체챰]/.test(tok)) return tok;

    // Siglas reales tipo USA/ONU/TV
    if (isAcronym(tok)) return tok.toUpperCase();

    // Soporte guiones
    const parts = tok.split("-");
    const casedParts = parts.map((p, partIdx) => {
      if (!/[A-Za-z횁횋횒횙횣횥횗찼챕챠처첬체챰]/.test(p)) return p;
      if (isAcronym(p)) return p.toUpperCase();

      const isFirstWord = (idx === 0 && partIdx === 0);
      return titleCaseWord(p, isFirstWord);
    });

    return casedParts.join("-");
  });

  return out.join(" ");
}

const jsonlds = extractJsonLd(html);
const flat = flattenGraph(jsonlds);
const item = pickBest(flat);

let titleExact = "";
let subtitle = "";
let author = "";

if (item) {
  titleExact = item.name || item.headline || "";
  subtitle = item.alternateName || item.subtitle || item.description || "";
  author = normalizeAuthor(item.author);
}

// Limpieza subtitle
if (subtitle && subtitle.length > 180) subtitle = subtitle.slice(0, 180).trim();

// Normaliza t챠tulo
titleExact = smartTitleCaseEs(titleExact);

// Fallbacks
if (!titleExact) titleExact = $json.query || "";
const link = item?.url || fallbackUrl || "";

return [{
  json: {
    titleExact: titleExact || "",
    subtitle: subtitle || "",
    author: author || "",
    link: link || ""
  }
}];
